import { Box, Button, Dialog, DialogActions, DialogContent, DialogTitle, FormHelperText, MenuItem, TextField } from '@material-ui/core'
import axios from 'axios'
import React, { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import Cookies from 'js-cookie'



export default function EditProfile() {
    const history = useNavigate();

    const id = Cookies.get('idLoggedIn')

    const showStudent = () => {
        const sendData = {
            updateID: id
        }
        axios.post('https://ursacapi.000webhostapp.com/api/getStudentID.php', JSON.stringify(sendData))
            .then(response => {
                setData(response.data[0])
            })
            .catch(err => console.log(err))
    }


    useEffect(() => {
        showStudent();
    }, []);

    const [data, setData] = useState({
        studentID: '',
        firstName: '',
        middleName: '',
        lastName: '',
        college: '',
        course: '',
        password: ''
    })









    const handleChange = (event) => {
        const name = event.target.name;
        const value = event.target.value;

        setData(data => ({ ...data, [name]: value }));
    }




    const handleSubmit = (e) => {
        e.preventDefault();
        const sendData = {
            studentID: data.studentID,
            firstName: data.firstName,
            middleName: data.middleName,
            lastName: data.lastName,
            college: data.college,
            course: data.course,
            password: data.password,
            id: id
        }

        axios.post('https://ursacapi.000webhostapp.com/api/updateStudent.php', JSON.stringify(sendData))
            .then((result) => {
                console.log(result.data)
            })
            .catch(err => console.log(err))
    };






    return (

        <Box>

            <center>

                {/* // STUDENT */}
                <div>
                    <form onSubmit={handleSubmit}>

                        <FormHelperText>Student ID</FormHelperText>
                        <TextField placeholder='Student ID' type="text" name='studentID' value={data.studentID} onChange={handleChange} fullWidth disabled />
                        <br /><br />

                        <FormHelperText>First Name</FormHelperText>
                        <TextField variant='outlined' placeholder='First Name' type="text" name='firstName' value={data.firstName} onChange={handleChange} fullWidth />
                        <br /><br />

                        <FormHelperText>Middle Name</FormHelperText>
                        <TextField variant='outlined' placeholder='Middle Name' type="text" name='middleName' value={data.middleName} onChange={handleChange} fullWidth />
                        <br /><br />

                        <FormHelperText>Last Name</FormHelperText>
                        <TextField variant='outlined' placeholder='Last Name' type="text" name='lastName' value={data.lastName} onChange={handleChange} fullWidth />
                        <br /><br />

                        <FormHelperText>College</FormHelperText>
                        <TextField variant='outlined' placeholder='College' type="text" name='college' value={data.college} onChange={handleChange} fullWidth />
                        <br /><br />

                        <FormHelperText>Course</FormHelperText>
                        <TextField variant='outlined' placeholder='Course' type="text" name='course' value={data.course} onChange={handleChange} fullWidth multiline />
                        <br /><br />

                        <FormHelperText>Password</FormHelperText>
                        <TextField variant='outlined' placeholder='Password' type="text" name='password' value={data.password} onChange={handleChange} fullWidth />
                        <br /><br />


                        <Button fullWidth type='submit' name='submit' variant='contained' color='secondary'> Edit Changes </Button>

                    </form>
                </div>
            </center>

            <Dialog
                open={true}
            >


                <DialogTitle>
                    Enter password to confirm
                </DialogTitle>

                <DialogContent>
                    <TextField label='Password' type='text' fullWidth />
                </DialogContent>

                <DialogActions>
                    <Button variant='contained' color='secondary'>Confirm</Button>
                    <Button variant='outlined' color='secondary'>Cancel</Button>
                </DialogActions>

            </Dialog>

        </Box>
    )
}
